/**
 * Webhook notification adapter — delivers notifications via HTTP POST.
 *
 * Formats notification payloads as JSON and POSTs them to a webhook URL.
 * Uses an in-memory transport by default (suitable for testing; swap for
 * a real HTTP client in production).
 *
 * Implements: NotificationAdapter
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationChannel, NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/** The JSON body sent to webhook endpoints. */
export interface WebhookDelivery {
  url: string;
  payload: WebhookPayloadBody;
  headers: Record<string, string>;
  deliveredAt: Date;
}

/** The JSON body structure POSTed to the webhook URL. */
export interface WebhookPayloadBody {
  notificationId: string;
  type: string;
  recipient: string;
  subject: string;
  body: string;
  metadata?: Record<string, unknown>;
  createdAt: string;
}

/** Options for configuring the webhook adapter. */
export interface WebhookAdapterOptions {
  /** Default timeout in milliseconds for webhook requests. */
  timeoutMs?: number;
  /** Custom headers to include in every webhook request. */
  defaultHeaders?: Record<string, string>;
  /**
   * Optional HTTP transport function. When provided, the adapter calls this
   * instead of storing deliveries in memory. Return true for success, false for failure.
   */
  httpPost?: (url: string, body: string, headers: Record<string, string>) => Promise<boolean>;
}

const URL_REGEX = /^https?:\/\/[^\s]+$/;

/**
 * Validate that a recipient string is a plausible webhook URL.
 */
export function validateWebhookUrl(url: string): { valid: boolean; error?: string } {
  if (!url || url.trim().length === 0) {
    return { valid: false, error: 'Webhook URL is empty' };
  }
  if (!URL_REGEX.test(url)) {
    return { valid: false, error: `Invalid webhook URL: ${url}` };
  }
  return { valid: true };
}

/**
 * Format a NotificationPayload into the JSON body sent to webhook endpoints.
 */
export function formatWebhookBody(payload: NotificationPayload): WebhookPayloadBody {
  return {
    notificationId: payload.id,
    type: payload.type,
    recipient: payload.recipient,
    subject: payload.subject,
    body: payload.body,
    metadata: payload.metadata ? { ...payload.metadata } : undefined,
    createdAt: payload.createdAt.toISOString(),
  };
}

export class WebhookNotificationAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'webhook';
  private logger = new Logger('WebhookAdapter');
  private deliveries: WebhookDelivery[] = [];
  private timeoutMs: number;
  private defaultHeaders: Record<string, string>;
  private httpPost?: (url: string, body: string, headers: Record<string, string>) => Promise<boolean>;

  constructor(options?: WebhookAdapterOptions) {
    this.timeoutMs = options?.timeoutMs ?? 5000;
    this.defaultHeaders = {
      'Content-Type': 'application/json',
      ...options?.defaultHeaders,
    };
    this.httpPost = options?.httpPost;
  }

  /**
   * Send a notification as a webhook POST.
   * Validates the URL, formats the payload, and delivers it.
   * In production, provide an httpPost transport; otherwise deliveries are stored in memory.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      // Validate recipient URL
      const validation = validateWebhookUrl(payload.recipient);
      if (!validation.valid) {
        this.logger.error(`URL validation failed: ${validation.error}`);
        return {
          success: false,
          channel: this.channel,
          notificationId: payload.id,
          error: validation.error!,
          deliveredAt: new Date(),
        };
      }

      // Format payload body
      const webhookBody = formatWebhookBody(payload);
      const headers = { ...this.defaultHeaders };

      // Deliver via transport or store in memory
      if (this.httpPost) {
        const success = await this.httpPost(payload.recipient, JSON.stringify(webhookBody), headers);
        if (!success) {
          this.logger.error(`Webhook POST failed for ${payload.recipient}`);
          return {
            success: false,
            channel: this.channel,
            notificationId: payload.id,
            error: `Webhook POST failed for ${payload.recipient}`,
            deliveredAt: new Date(),
          };
        }
      }

      const delivery: WebhookDelivery = {
        url: payload.recipient,
        payload: webhookBody,
        headers,
        deliveredAt: new Date(),
      };

      this.deliveries.push(delivery);
      this.logger.info(`Webhook delivered to ${payload.recipient}`);

      return {
        success: true,
        channel: this.channel,
        notificationId: payload.id,
        deliveredAt: delivery.deliveredAt,
      };
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Unknown webhook error';
      this.logger.error(`Failed to send webhook to ${payload.recipient}: ${errorMessage}`);

      return {
        success: false,
        channel: this.channel,
        notificationId: payload.id,
        error: errorMessage,
        deliveredAt: new Date(),
      };
    }
  }

  /** Get all delivered webhooks. Useful for testing. */
  getDeliveries(): WebhookDelivery[] {
    return [...this.deliveries];
  }

  /** Clear delivered webhooks. Useful for testing. */
  clearDeliveries(): void {
    this.deliveries = [];
  }

  /** Get the configured timeout in milliseconds. */
  getTimeoutMs(): number {
    return this.timeoutMs;
  }

  /** Get the configured default headers. */
  getDefaultHeaders(): Record<string, string> {
    return { ...this.defaultHeaders };
  }
}

