import { describe, it, expect, beforeEach } from 'vitest';
import {
  WebhookNotificationAdapter,
  validateWebhookUrl,
  formatWebhookBody,
} from '../../src/adapters/webhook.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides: Partial<NotificationPayload> = {}): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order_confirmation',
    recipient: 'https://hooks.example.com/notify',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    metadata: { orderId: 'order-1', userId: 'user-1' },
    createdAt: new Date('2026-01-01T00:00:00Z'),
    ...overrides,
  };
}

describe('validateWebhookUrl', () => {
  it('should accept a valid https URL', () => {
    expect(validateWebhookUrl('https://hooks.example.com/notify')).toEqual({ valid: true });
  });

  it('should accept a valid http URL', () => {
    expect(validateWebhookUrl('http://localhost:3000/webhook')).toEqual({ valid: true });
  });

  it('should reject an empty string', () => {
    const result = validateWebhookUrl('');
    expect(result.valid).toBe(false);
    expect(result.error).toContain('empty');
  });

  it('should reject a URL without protocol', () => {
    const result = validateWebhookUrl('hooks.example.com/notify');
    expect(result.valid).toBe(false);
    expect(result.error).toContain('Invalid');
  });

  it('should reject a non-http URL', () => {
    const result = validateWebhookUrl('ftp://example.com/webhook');
    expect(result.valid).toBe(false);
    expect(result.error).toContain('Invalid');
  });
});

describe('formatWebhookBody', () => {
  it('should format payload into webhook body', () => {
    const payload = makePayload();
    const body = formatWebhookBody(payload);

    expect(body.notificationId).toBe('notif-0001');
    expect(body.type).toBe('order_confirmation');
    expect(body.recipient).toBe('https://hooks.example.com/notify');
    expect(body.subject).toBe('Order Confirmation: order-1');
    expect(body.body).toContain('Widget x2');
    expect(body.createdAt).toBe('2026-01-01T00:00:00.000Z');
  });

  it('should include metadata when present', () => {
    const payload = makePayload({ metadata: { orderId: 'order-42' } });
    const body = formatWebhookBody(payload);

    expect(body.metadata).toEqual({ orderId: 'order-42' });
  });

  it('should set metadata to undefined when not present', () => {
    const payload = makePayload({ metadata: undefined });
    const body = formatWebhookBody(payload);

    expect(body.metadata).toBeUndefined();
  });

  it('should create a defensive copy of metadata', () => {
    const metadata = { key: 'value' };
    const payload = makePayload({ metadata });
    const body = formatWebhookBody(payload);

    expect(body.metadata).toEqual(metadata);
    expect(body.metadata).not.toBe(metadata);
  });
});

describe('WebhookNotificationAdapter', () => {
  let adapter: WebhookNotificationAdapter;

  beforeEach(() => {
    adapter = new WebhookNotificationAdapter();
  });

  it('should have channel "webhook"', () => {
    expect(adapter.channel).toBe('webhook');
  });

  it('should use default config values', () => {
    expect(adapter.getTimeoutMs()).toBe(5000);
    expect(adapter.getDefaultHeaders()).toEqual({ 'Content-Type': 'application/json' });
  });

  it('should accept custom options', () => {
    const custom = new WebhookNotificationAdapter({
      timeoutMs: 10000,
      defaultHeaders: { 'X-Api-Key': 'secret123' },
    });
    expect(custom.getTimeoutMs()).toBe(10000);
    expect(custom.getDefaultHeaders()).toEqual({
      'Content-Type': 'application/json',
      'X-Api-Key': 'secret123',
    });
  });

  describe('send', () => {
    it('should deliver a valid notification and return success', async () => {
      const payload = makePayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.channel).toBe('webhook');
      expect(result.notificationId).toBe('notif-0001');
      expect(result.deliveredAt).toBeInstanceOf(Date);
      expect(result.error).toBeUndefined();
    });

    it('should store the delivery', async () => {
      const payload = makePayload();
      await adapter.send(payload);

      const deliveries = adapter.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]!.url).toBe('https://hooks.example.com/notify');
      expect(deliveries[0]!.payload.notificationId).toBe('notif-0001');
      expect(deliveries[0]!.payload.type).toBe('order_confirmation');
      expect(deliveries[0]!.headers['Content-Type']).toBe('application/json');
      expect(deliveries[0]!.deliveredAt).toBeInstanceOf(Date);
    });

    it('should fail for invalid URL', async () => {
      const payload = makePayload({ recipient: 'not-a-url' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid webhook URL');
      expect(adapter.getDeliveries()).toHaveLength(0);
    });

    it('should fail for empty URL', async () => {
      const payload = makePayload({ recipient: '' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('empty');
    });

    it('should handle multiple sends', async () => {
      await adapter.send(makePayload({ id: 'n1', recipient: 'https://a.com/hook' }));
      await adapter.send(makePayload({ id: 'n2', recipient: 'https://b.com/hook' }));

      expect(adapter.getDeliveries()).toHaveLength(2);
    });

    it('should clear deliveries', async () => {
      await adapter.send(makePayload());
      adapter.clearDeliveries();

      expect(adapter.getDeliveries()).toHaveLength(0);
    });

    it('should return defensive copy from getDeliveries', async () => {
      await adapter.send(makePayload());
      const d1 = adapter.getDeliveries();
      const d2 = adapter.getDeliveries();

      expect(d1).not.toBe(d2);
      expect(d1).toEqual(d2);
    });

    it('should use custom httpPost transport when provided', async () => {
      const calls: { url: string; body: string }[] = [];
      const customAdapter = new WebhookNotificationAdapter({
        httpPost: async (url, body) => {
          calls.push({ url, body });
          return true;
        },
      });

      const payload = makePayload();
      const result = await customAdapter.send(payload);

      expect(result.success).toBe(true);
      expect(calls).toHaveLength(1);
      expect(calls[0]!.url).toBe('https://hooks.example.com/notify');
      const parsed = JSON.parse(calls[0]!.body);
      expect(parsed.notificationId).toBe('notif-0001');
    });

    it('should return failure when httpPost returns false', async () => {
      const customAdapter = new WebhookNotificationAdapter({
        httpPost: async () => false,
      });

      const payload = makePayload();
      const result = await customAdapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('Webhook POST failed');
    });

    it('should handle httpPost throwing an error', async () => {
      const customAdapter = new WebhookNotificationAdapter({
        httpPost: async () => { throw new Error('Connection refused'); },
      });

      const payload = makePayload();
      const result = await customAdapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toBe('Connection refused');
    });
  });
});

